import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';

const Login = () => {
    const [isLogin, setIsLogin] = useState(true);
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [confirmPassword, setConfirmPassword] = useState('');
    const [rememberMe, setRememberMe] = useState(false);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');
    const navigate = useNavigate();

    const validateForm = () => {
        if (!email || !email.includes('@')) {
            setError('Please enter a valid email address');
            return false;
        }
        if (!password || password.length < 6) {
            setError('Password must be at least 6 characters long');
            return false;
        }
        if (!isLogin && password !== confirmPassword) {
            setError('Passwords do not match');
            return false;
        }
        return true;
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setError('');

        if (!validateForm()) return;

        setLoading(true);
        try {
            // Simulate API call
            await new Promise(resolve => setTimeout(resolve, 1500));

            // Store in localStorage
            localStorage.setItem('user', JSON.stringify({
                email,
                name: email.split('@')[0]
            }));

            // Redirect to dashboard
            navigate('/dashboard');
        } catch (err) {
            setError('Authentication failed. Please try again.');
        } finally {
            setLoading(false);
        }
    };

    const handleGoogleAuth = () => {
        alert('Google Auth would be implemented here with your Google Client ID');
        // window.location.href = 'https://accounts.google.com/o/oauth2/v2/auth?client_id=YOUR_CLIENT_ID&redirect_uri=YOUR_REDIRECT_URI&response_type=code&scope=email%20profile';
    };

    const handleForgotPassword = () => {
        if (!email) {
            setError('Please enter your email address');
            return;
        }
        alert(`Password reset link sent to ${email}`);
    };

    return (
        <div style={styles.container}>
            <style>{`
                @keyframes fadeIn {
                    from {
                        opacity: 0;
                        transform: translateY(20px);
                    }
                    to {
                        opacity: 1;
                        transform: translateY(0);
                    }
                }

                @keyframes spin {
                    to { 
                        transform: rotate(360deg); 
                    }
                }

                .auth-card {
                    animation: fadeIn 0.6s ease-out;
                }

                .loading-spinner {
                    display: inline-block;
                    width: 20px;
                    height: 20px;
                    border: 3px solid rgba(255, 255, 255, 0.3);
                    border-radius: 50%;
                    border-top-color: #ffffff;
                    animation: spin 1s ease-in-out infinite;
                }
            `}</style>

            {/* Left Section - Branding */}
            <div style={styles.brandSection}>
                <div style={styles.brandContent}>
                    <h1 style={styles.brandTitle}>
                        <span style={styles.titlePart1}>TICKET</span>
                        <span style={styles.titlePart2}>MANAGEMENT</span>
                        <span style={styles.titlePart3}>SYSTEM</span>
                    </h1>
                    <p style={styles.brandSubtitle}>
                        Streamline your workflow with our powerful ticket management solution
                    </p>
                    <div style={styles.brandFeatures}>
                        <div style={styles.feature}>
                            <span style={styles.featureIcon}>✅</span>
                            <span>Secure Authentication</span>
                        </div>
                        <div style={styles.feature}>
                            <span style={styles.featureIcon}>⚡</span>
                            <span>Real-time Updates</span>
                        </div>
                        <div style={styles.feature}>
                            <span style={styles.featureIcon}>🔒</span>
                            <span>Enterprise Grade Security</span>
                        </div>
                    </div>
                </div>
                <div style={styles.brandFooter}>
                    <p>© 2024 TMS Pro. All rights reserved.</p>
                </div>
            </div>

            {/* Right Section - Authentication Form */}
            <div style={styles.authSection}>
                <div className="auth-card" style={styles.authCard}>
                    <div style={styles.authHeader}>
                        <h2 style={styles.authTitle}>
                            {isLogin ? 'WELCOME BACK' : 'CREATE ACCOUNT'}
                        </h2>
                        <p style={styles.authSubtitle}>
                            {isLogin ? 'Please enter your details' : 'Start your journey with us'}
                        </p>
                    </div>

                    {error && (
                        <div style={styles.errorAlert}>
                            <span style={styles.errorIcon}>⚠️</span>
                            <span>{error}</span>
                        </div>
                    )}

                    <form onSubmit={handleSubmit} style={styles.authForm}>
                        <div style={styles.formGroup}>
                            <label htmlFor="email" style={styles.formLabel}>Email</label>
                            <input
                                type="email"
                                id="email"
                                style={styles.formInput}
                                placeholder="Enter your email"
                                value={email}
                                onChange={(e) => setEmail(e.target.value)}
                                required
                            />
                        </div>

                        <div style={styles.formGroup}>
                            <label htmlFor="password" style={styles.formLabel}>Password</label>
                            <input
                                type="password"
                                id="password"
                                style={styles.formInput}
                                placeholder="Enter your password"
                                value={password}
                                onChange={(e) => setPassword(e.target.value)}
                                required
                            />
                        </div>

                        {!isLogin && (
                            <div style={styles.formGroup}>
                                <label htmlFor="confirmPassword" style={styles.formLabel}>Confirm Password</label>
                                <input
                                    type="password"
                                    id="confirmPassword"
                                    style={styles.formInput}
                                    placeholder="Confirm your password"
                                    value={confirmPassword}
                                    onChange={(e) => setConfirmPassword(e.target.value)}
                                    required
                                />
                            </div>
                        )}

                        {isLogin && (
                            <div style={styles.formOptions}>
                                <label style={styles.checkboxLabel}>
                                    <input
                                        type="checkbox"
                                        checked={rememberMe}
                                        onChange={(e) => setRememberMe(e.target.checked)}
                                        style={{ display: 'none' }}
                                    />
                                    <span style={styles.checkboxCustom}></span>
                                    <span>Remember me</span>
                                </label>
                                <button
                                    type="button"
                                    style={styles.forgotPassword}
                                    onClick={handleForgotPassword}
                                >
                                    Forgot password?
                                </button>
                            </div>
                        )}

                        <button
                            type="submit"
                            style={{
                                ...styles.submitBtn,
                                opacity: loading ? 0.6 : 1,
                                cursor: loading ? 'not-allowed' : 'pointer'
                            }}
                            disabled={loading}
                        >
                            {loading ? (
                                <span className="loading-spinner"></span>
                            ) : isLogin ? (
                                'Sign in'
                            ) : (
                                'Sign up'
                            )}
                        </button>

                        <div style={styles.divider}>
                            <span style={styles.dividerLine}></span>
                            <span style={styles.dividerText}>OR CONTINUE WITH</span>
                            <span style={styles.dividerLine}></span>
                        </div>

                        <button
                            type="button"
                            style={styles.googleBtn}
                            onClick={handleGoogleAuth}
                        >
                            <div style={styles.googleIcon}>
                                G
                            </div>
                            Sign in with Google
                        </button>

                        <div style={styles.authSwitch}>
                            <span>
                                {isLogin ? "Don't have an account?" : "Already have an account?"}
                            </span>
                            <button
                                type="button"
                                style={styles.switchBtn}
                                onClick={() => {
                                    setIsLogin(!isLogin);
                                    setError('');
                                    setConfirmPassword('');
                                }}
                            >
                                {isLogin ? 'Sign up for free!' : 'Sign in'}
                            </button>
                        </div>
                    </form>

                    <div style={styles.progressContainer}>
                        <div style={styles.progressBar}>
                            <div 
                                style={{...styles.progressFill, width: '73%'}}
                            ></div>
                        </div>
                        <span style={styles.progressText}>73%</span>
                    </div>
                </div>
            </div>
        </div>
    );
};

const styles = {
    container: {
